import random

CONCEPT_TYPE = "geometry.line_intersection_distance"
CONCEPT_GROUP = "geometry"

def generate(seed):
    rng = random.Random(seed)

    # Define the domain parameters
    a = rng.randint(1, 10)  # x-coordinate of point A
    b = rng.randint(1, 10)  # y-coordinate of point A
    c = rng.randint(1, 10)  # x-coordinate of point B
    d = rng.randint(1, 10)  # y-coordinate of point B
    e = rng.randint(1, 10)  # x-coordinate of point C
    f = rng.randint(1, 10)  # y-coordinate of point C

    # Calculate the distance between two lines
    def distance_between_lines(x1, y1, x2, y2, x3, y3, x4, y4):
        denominator = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)
        if denominator == 0:
            return 0  # Lines are parallel or coincident
        else:
            return abs((x1 - x2) * (y2 - y3) - (y1 - y2) * (x2 - x3)) / abs(denominator)

    # Calculate the distance between the lines defined by points A and B, and points C and D
    distance = distance_between_lines(a, b, c, d, e, f, e, f)

    # Add a case analysis branch
    if random.random() < 0.5:
        problem = (
            f"Given points A = ({a}, {b}), B = ({c}, {d}), C = ({e}, {f}), and D = ({e}, {f}), find the distance between the lines defined by AB and CD. "
            f"Additionally, explain why this distance is zero when the lines are parallel or coincident."
        )
    else:
        problem = (
            f"Given points A = ({a}, {b}), B = ({c}, {d}), C = ({e}, {f}), and D = ({e}, {f}), find the distance between the lines defined by AB and CD. "
            f"Explain why the distance is non-zero when the lines are not parallel or coincident."
        )

    return problem, str(distance)
